B.RQ=new A.eg("W\xe4rmeschied","Styrodur-Schied zur Brutraum-Einengung.\nWichtig f\xfcr die langen Winter auf 1570 m.\nVolksst\xe4rke an Raumgr\xf6sse angepasst.",B.nU,!1,null)
