B.RR=new A.eg("Transport nach Arosa","Max. 40 kg f\xfcr eine Person tragbar.\n63cm Kessel passt in jeden Kombi.\n230V Haushaltsstrom ausreichend.\nBei z\xe4hfl\xfcssigem Berghonig etwas l\xe4nger schleudern.",B.uu,!1,null)
B.RS=new A.eg("Bio-kompatibel (Holz)","Weymouthskiefer, 25-30 mm Wandst\xe4rke.\nNat\xfcrliches Material, kein Styropor/Kunststoff.\nErf\xfcllt Bio-Suisse Anforderungen.",B.nP,!0,null)
B.RT=new A.eg("Registrierungspflicht","Alle Bienenst\xe4nde m\xfcssen beim ALT GR registriert werden.\nMeldepflicht bei Standortwechsel.",B.ud,!1,null)
B.RU=new A.eg("Herausforderungen","\u2022 Kurze Saison (ca. 3-4 Monate)\n\u2022 Lange Winter (Nov-M\xe4rz Winterruhe)\n\u2022 40-45 Tage Verschiebung vs. Tallagen\n\u2022 Heftige Wetterwechsel\n\u2022 Grosse Wintervorr\xe4te n\xf6tig (15-20 kg Sirup/Volk)",B.uu,!1,null)
B.RV=new A.eg("Deckelisolation","Styrodur 30-50 mm unter dem Blechdeckel.\nVerhindert Kondenswasser im Winter.\nSch\xfctzt vor extremen Temperaturschwankungen.",B.uo,!1,null)
B.RW=new A.eg("Vorteile","\u2022 Premium-Honig (Alpenbl\xfcten, Alpenrosen)\n\u2022 Weniger Pestizidbelastung\n\u2022 Geringerer Krankheitsdruck\n\u2022 Hohe Preise erzielbar (CHF 18-25/500g)",B.nT,!0,null)
